-- 185c_dream_symbols_i18n_seed.sql
-- FAZ 4 devam: kalan rüya sembol kataloğu için EN+DE i18n.
-- 185_dream_seed.sql ve dream_symbol_i18n tablosu sonrasında çalışır.

INSERT INTO dream_symbol_i18n (id, symbol_id, locale, name, meaning, category)
SELECT UUID(), s.id, v.locale, v.name, v.meaning, v.category
FROM dream_symbols s
JOIN (
  SELECT 'angel' slug, 'en' locale, 'Angel' name, 'Protection, divine message and higher awareness.' meaning, '["good_news","intuition"]' category
  UNION ALL SELECT 'angel','de','Engel','Schutz, göttliche Botschaft und höheres Bewusstsein.','["gute_nachricht","intuition"]'
  UNION ALL SELECT 'bee','en','Bee','Hard work, community and sweet results.' ,'["career","good_news"]'
  UNION ALL SELECT 'bee','de','Biene','Fleiß, Gemeinschaft und süße Ergebnisse.','["karriere","gute_nachricht"]'
  UNION ALL SELECT 'being_lost','en','Being Lost','Loss of direction, confusion and uncertainty.','["warning","psychological"]'
  UNION ALL SELECT 'being_lost','de','Sich verirren','Orientierungsverlust, Verwirrung und Unsicherheit.','["warnung","psychologisch"]'
